    if not api_key:
        return '请先输入API Key'

    endpoint = LLM_ENDPOINTS.get(provider)
    model = LLM_MODELS.get(provider, 'model')

    if not endpoint:
        return '未知服务商'

    try:
        if provider == 'claude':
            headers = {
                'x-api-key': api_key,
                'anthropic-version': '2023-06-01',
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
            }
        else:
            headers = {
                'Authorization': 'Bearer %s' % api_key,
                'Content-Type': 'application/json',
            }
            data = {
                'model': model,
                'max_tokens': 10,
                'messages': [{'role': 'user', 'content': 'hi'}],
            }

        resp = requests.post(endpoint, headers=headers, json=data, timeout=15)

        if resp.status_code in (200, 201):
            return '%s: 连接成功' % provider
        else:
            return '%s: HTTP %d - %s' % (provider, resp.status_code, resp.text[:60])

    except Exception as e:
        return '测试失败: %s' % str(e)[:80]


# ===== Java调用入口 =====
def run_compare(audio_text, doc_path):
    """主入口：接收ASR文本，进行文本对比"""
    paragraphs = parse_docx(doc_path)
    doc_text = '\n'.join(paragraphs)
    summary, diffs = compare_texts(audio_text, doc_text)
    return {'summary': summary, 'details': '\n'.join(diffs)}

