def _transcribe_baidu_chunked(filepath, token):
    """百度语音分段转写"""
    import tempfile, subprocess
    tmpdir = tempfile.mkdtemp()
    chunk_pattern = os.path.join(tmpdir, 'chunk_%03d.wav')

    try:
        subprocess.run([
            'ffmpeg', '-i', filepath, '-f', 'segment', '-segment_time', '50',
            '-ac', '1', '-ar', '16000', '-acodec', 'pcm_s16le', '-y', chunk_pattern
        ], capture_output=True, timeout=120)
    except:
        # 没有ffmpeg就用Python切分
        chunks = _split_wav_simple(filepath, tmpdir, 50)
    else:
        chunks = sorted([os.path.join(tmpdir, f) for f in os.listdir(tmpdir) if f.startswith('chunk_')])

    if not chunks:
        raise Exception('音频分段失败')

    results = []
    for chunk in chunks:
        with open(chunk, 'rb') as f:
            data = f.read()
        if len(data) < 100:
            continue
        try:
            r = requests.post('https://vop.baidu.com/server_api', json={
                'format': 'wav', 'rate': 16000, 'channel': 1,
                'cuid': 'voicedoc_apk', 'token': token,
                'speech': base64.b64encode(data).decode(),
                'len': len(data), 'dev_pid': 1537
            }, timeout=60).json()
            if r.get('err_no', -1) == 0:
                text = ''.join(r.get('result', []))
                if text.strip():
                    results.append(text)
        except:
            pass
        try:
            os.remove(chunk)
        except:
            pass
    try:
        os.rmdir(tmpdir)
    except:
        pass
    return ''.join(results) if results else '分段识别全部失败'


def _split_wav_simple(filepath, output_dir, segment_sec):
    """简易WAV切分"""
    try:
        import wave
        with wave.open(filepath, 'rb') as wf:
            params = wf.getparams()
            framerate = wf.getframerate()
            frames_per_chunk = int(framerate * segment_sec)
            total = wf.getnframes()
            chunks = []
            i = 0
            while wf.tell() < total:
                data = wf.readframes(frames_per_chunk)
                if len(data) < framerate:  # 不足1秒
                    break
                path = os.path.join(output_dir, 'chunk_%03d.wav' % i)
                with wave.open(path, 'wb') as out:
                    out.setparams(params)
                    out.writeframes(data)
                chunks.append(path)
                i += 1
            return chunks
    except:
        return []


