def transcribe_funasr(filepath, server_url):
    """FunASR局域网服务"""
    try:
        r = requests.get('%s/health' % server_url, timeout=3)
        if r.status_code != 200:
            raise Exception('FunASR服务未响应')
    except requests.exceptions.ConnectionError:
        raise Exception('无法连接FunASR服务(%s)\n请确认手机和电脑在同一WiFi' % server_url)

    with open(filepath, 'rb') as f:
        resp = requests.post('%s/transcribe_file' % server_url,
            files={'file': (os.path.basename(filepath), f)}, timeout=600)

    if resp.status_code == 404:
        resp = requests.post('%s/transcribe' % server_url,
            json={'file_path': os.path.abspath(filepath)}, timeout=600)

    data = resp.json()
    if not data.get('success'):
        raise Exception(data.get('error', 'FunASR转写失败'))
    return data.get('text', '')


