470→    // ===== 线性插值重采样 =====
471→    private float[] resample(float[] input, int fromRate, int toRate) {
472→        double ratio = (double) fromRate / toRate;
473→        int outputLen = (int) (input.length / ratio);
474→        float[] output = new float[outputLen];
475→        for (int i = 0; i < outputLen; i++) {
476→            double srcIdx = i * ratio;
477→            int idx = (int) srcIdx;
478→            double frac = srcIdx - idx;
479→            if (idx + 1 < input.length) {
480→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
481→            } else if (idx < input.length) {
482→                output[i] = input[idx];
483→            }
484→        }
485→        return output;
486→    }
