def run_compare_with_timestamps(audio_text, doc_text, audio_timestamps=None):
    """带时间戳的对比：返回结构化差异列表（Java侧调用）

    Args:
        audio_text: ASR转写文本
        doc_text: 原始文档文本
        audio_timestamps: 词级时间戳列表 [{'word': '字', 'start': 秒, 'end': 秒}, ...]

    Returns:
        {
            'summary': '统计摘要',
            'diffs': [
                {'type': 'mismatch', 'docText': '原文', 'audioText': '录音', 'time_start': 12.3, 'time_end': 15.6},
                ...
            ]
        }
    """
    from difflib import SequenceMatcher

    paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]
    doc_text_full = '\n'.join(paragraphs)

    # 分词
    audio_words = [c for c in audio_text if c.strip()]
    doc_words = [c for c in doc_text_full if c.strip()]

    # 构建时间戳映射（字符级 -> 时间）
    ts_map = {}
    if audio_timestamps:
        offset = 0
        for ts in audio_timestamps:
            word = ts.get('word', '')
            start = ts.get('start', 0)
            end = ts.get('end', start)
            for i, ch in enumerate(word):
                ts_map[offset + i] = {'start': start, 'end': end}
            offset += len(word)

    # 音频字符偏移
    audio_offsets = []
    off = 0
    for w in audio_words:
        audio_offsets.append(off)
        off += len(w)

    # 序列比对
    matcher = SequenceMatcher(None, doc_words, audio_words)
    diffs = []

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue

        doc_frag = ''.join(doc_words[i1:i2])
        audio_frag = ''.join(audio_words[j1:j2])

        # 过滤填充词
        if tag == 'insert' and audio_frag in FILLER_WORDS:
            continue
        if tag == 'delete' and doc_frag in FILLER_WORDS:
            continue
        if tag == 'replace':
            if doc_frag in FILLER_WORDS and audio_frag in FILLER_WORDS:
                continue
            if _same_pinyin(doc_frag, audio_frag):
                continue

        if not doc_frag.strip() and not audio_frag.strip():
            continue

        # 获取时间戳
        time_start = time_end = None
        if j1 < len(audio_offsets) and ts_map:
            char_off = audio_offsets[j1]
            if char_off in ts_map:
                time_start = ts_map[char_off]['start']
            if j2 > 0 and j2 - 1 < len(audio_offsets):
                end_off = audio_offsets[j2 - 1]
                if end_off in ts_map:
                    time_end = ts_map[end_off]['end']

        diff_entry = {
            'type': 'mismatch' if tag == 'replace' else ('missing' if tag == 'delete' else 'extra'),
            'docText': doc_frag,
            'audioText': audio_frag,
        }
        if time_start is not None:
            diff_entry['time_start'] = time_start
        if time_end is not None:
            diff_entry['time_end'] = time_end
        diffs.append(diff_entry)

    # 统计
    n_mis = sum(1 for d in diffs if d['type'] == 'mismatch')
    n_miss = sum(1 for d in diffs if d['type'] == 'missing')
    n_ext = sum(1 for d in diffs if d['type'] == 'extra')

    summary = '共%d处差异：%d处误读，%d处漏读，%d处多读' % (len(diffs), n_mis, n_miss, n_ext)

    return {'summary': summary, 'diffs': diffs}

